package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class ReflectionAccessFilterHelperTest {

  @Test
  void testIsAnyPlatformType_withAndroidType() throws Exception {
    // Since android.app.Activity is not available in the classpath,
    // test with a dummy class name starting with "android."
    Class<?> dummyAndroidClass = new Class<>() {
      @Override
      public String getName() {
        return "android.app.Activity";
      }
    }.getClass();

    // Use a proxy Class object that returns "android.app.Activity" for getName()
    Class<?> proxyClass = new Class<Object>() {
      @Override
      public String getName() {
        return "android.app.Activity";
      }
    }.getClass();

    // But we can't override getName() of Class, so instead create a subclass of ClassLoader
    // and load a dummy class with name starting with "android." dynamically.

    // The simplest fix: create a proxy Class via a dynamic proxy or subclass is impossible.
    // So, instead, test by creating a custom Class object via a helper method.

    // Alternative: Use a subclass of ClassLoader to define a dummy class with android prefix
    Class<?> androidLikeClass = new DummyClassLoader().loadClass("android.app.Activity");

    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(androidLikeClass));
  }

  @Test
  void testIsAnyPlatformType_withKotlinType() throws Exception {
    // Use reflection to get kotlin.Unit class to avoid compile error
    Class<?> kotlinClass;
    try {
      kotlinClass = Class.forName("kotlin.Unit");
    } catch (ClassNotFoundException e) {
      // If kotlin.Unit class is not available in classpath, skip test
      return;
    }
    // kotlin.Unit name starts with "kotlin."
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinClass));
  }

  @Test
  void testIsAnyPlatformType_withKotlinxType() throws Exception {
    // Create a dummy class with name starting with "kotlinx."
    Class<?> kotlinxLikeClass = new DummyClassLoader().loadClass("kotlinx.coroutines.CoroutineScope");
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinxLikeClass));
  }

  @Test
  void testIsAnyPlatformType_withScalaType() throws Exception {
    // Create a dummy class with name starting with scala.
    Class<?> scalaLikeClass = new DummyClassLoader().loadClass("scala.collection.Seq$");
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(scalaLikeClass));
  }

  @Test
  void testIsAnyPlatformType_withNonPlatformType() {
    assertFalse(ReflectionAccessFilterHelper.isAnyPlatformType(String.class));
  }

  // Helper class loader to define dummy classes with desired names
  static class DummyClassLoader extends ClassLoader {
    @Override
    protected Class<?> findClass(String name) throws ClassNotFoundException {
      if (name.startsWith("android.") ||
          name.startsWith("kotlinx.") ||
          name.startsWith("scala.")) {
        byte[] classBytes = generateEmptyClassBytes(name);
        return defineClass(name, classBytes, 0, classBytes.length);
      }
      throw new ClassNotFoundException(name);
    }

    // Generate minimal bytecode for an empty class with given name.
    // This is a minimal valid class byte array for a public class with no members.
    private byte[] generateEmptyClassBytes(String className) {
      /*
       * Use ASM or manual byte array for a minimal class:
       * For simplicity, use a hardcoded bytecode for:
       * public class <className> {}
       *
       * But className must be converted to internal form with slashes.
       */

      String internalName = className.replace('.', '/');

      // Using ASM would be easier, but since we can't add dependencies, use a pre-generated bytecode.
      // Here's a minimal class bytecode for public class Dummy {}:
      // We'll patch the class name in the bytecode.

      // Precompiled minimal class bytecode for:
      // public class Dummy {}
      // Hex bytes:
      // CAFEBABE 00000034 0012000A 09000B00 0C07000D
      // 07000E01 0006<name>...

      // Instead, use a small runtime ASM here:

      // As we can't use ASM or external libs, let's generate a minimal class bytecode manually.

      // This is a minimal class bytecode for a public class with no superinterfaces and no methods:
      // Magic number and version
      // Constant pool with class name and superclass java/lang/Object
      // Class access flags: public super
      // This class extends java/lang/Object
      // No fields, no methods

      // This bytecode was generated by ASM for a class named Dummy
      // We'll replace the class name in constant pool.

      try {
        java.io.ByteArrayOutputStream baos = new java.io.ByteArrayOutputStream();
        java.io.DataOutputStream dos = new java.io.DataOutputStream(baos);

        dos.writeInt(0xCAFEBABE); // magic
        dos.writeInt(0x00000034); // version: 52 (Java 8)

        // Constant pool count: 12
        dos.writeShort(12);

        // 1: Utf8 class name
        dos.writeByte(1);
        dos.writeUTF(internalName);

        // 2: Class #1
        dos.writeByte(7);
        dos.writeShort(1);

        // 3: Utf8 superclass name "java/lang/Object"
        dos.writeByte(1);
        dos.writeUTF("java/lang/Object");

        // 4: Class #3
        dos.writeByte(7);
        dos.writeShort(3);

        // 5: Utf8 "<init>"
        dos.writeByte(1);
        dos.writeUTF("<init>");

        // 6: Utf8 "()V"
        dos.writeByte(1);
        dos.writeUTF("()V");

        // 7: Utf8 "Code"
        dos.writeByte(1);
        dos.writeUTF("Code");

        // 8: NameAndType #5:#6
        dos.writeByte(12);
        dos.writeShort(5);
        dos.writeShort(6);

        // 9: Methodref #4.#8
        dos.writeByte(10);
        dos.writeShort(4);
        dos.writeShort(8);

        // 10: Utf8 "LineNumberTable"
        dos.writeByte(1);
        dos.writeUTF("LineNumberTable");

        // 11: Utf8 "SourceFile"
        dos.writeByte(1);
        dos.writeUTF("SourceFile");

        // 12: Utf8 "Dummy.java"
        dos.writeByte(1);
        dos.writeUTF("Dummy.java");

        // Access flags: public super
        dos.writeShort(0x0021);

        // This class: #2
        dos.writeShort(2);

        // Super class: #4
        dos.writeShort(4);

        // Interfaces count: 0
        dos.writeShort(0);

        // Fields count: 0
        dos.writeShort(0);

        // Methods count: 1
        dos.writeShort(1);

        // Method: public <init>()V
        dos.writeShort(0x0001); // access flags: public
        dos.writeShort(5); // name_index: <init>
        dos.writeShort(6); // descriptor_index: ()V
        dos.writeShort(1); // attributes_count

        // Attribute: Code
        dos.writeShort(7); // attribute_name_index: Code
        dos.writeInt(17); // attribute_length

        dos.writeShort(1); // max_stack
        dos.writeShort(1); // max_locals
        dos.writeInt(5);   // code_length

        // bytecode:
        // 0: aload_0
        // 1: invokespecial java/lang/Object.<init> ()V
        // 4: return
        dos.writeByte(0x2A); // aload_0
        dos.writeByte(0xB7); // invokespecial
        dos.writeShort(9);   // methodref #9
        dos.writeByte(0xB1); // return

        dos.writeShort(0); // exception_table_length
        dos.writeShort(1); // attributes_count

        // LineNumberTable attribute
        dos.writeShort(10); // attribute_name_index: LineNumberTable
        dos.writeInt(4);    // attribute_length
        dos.writeShort(0);  // start_pc
        dos.writeShort(1);  // line_number

        // Class attributes count: 1
        dos.writeShort(1);

        // SourceFile attribute
        dos.writeShort(11); // attribute_name_index: SourceFile
        dos.writeInt(2);    // attribute_length
        dos.writeShort(12); // sourcefile_index: Dummy.java

        dos.flush();
        return baos.toByteArray();
      } catch (Exception e) {
        throw new RuntimeException(e);
      }
    }
  }
}
